const getJobSuggestions=(emp,paths)=>{const w=emp.role.toLowerCase().split(/\s+/);const dp=paths.filter(p=>{const dm=emp.dept.toLowerCase().includes(p.domain.toLowerCase().split(" ")[0])||p.domain.toLowerCase().includes(emp.dept.toLowerCase().split(" ")[0]);const rm=p.steps.some(s=>w.some(x=>x.length>2&&s.title.toLowerCase().includes(x)));return dm||rm;});const r=new Set();dp.forEach(p=>{let f=false;p.steps.forEach(s=>{if(f&&r.size<15)r.add(s.title);if(w.some(x=>x.length>2&&s.title.toLowerCase().includes(x)))f=true;});if(r.size<15)r.add(p.steps[p.steps.length-1].title);});if(r.size<5)dp.slice(0,5).forEach(p=>p.steps.slice(-2).forEach(s=>r.add(s.title)));return[...r].slice(0,12);};

