const Side=({active,go,persona,onLogout})=>(<div style={{width:200,background:T.axaBlue,display:"flex",flexDirection:"column",flexShrink:0}}><div style={{padding:"14px 14px 10px",borderBottom:"1px solid rgba(255,255,255,.1)"}}><div style={{fontFamily:FH,fontSize:13,fontWeight:700,color:"#fff"}}>SMART Mobility</div><div style={{fontSize:8,color:"rgba(255,255,255,.4)",letterSpacing:1}}>AXA GROUP OPS</div></div><div style={{flex:1,padding:"4px 0",overflowY:"auto"}}>{NAV.filter(n=>(persona?.access||[]).includes(n.k)).map(n=>(<div key={n.k} onClick={()=>go(n.k)} style={{display:"flex",alignItems:"center",gap:7,padding:"8px 14px",cursor:"pointer",background:active===n.k?"rgba(255,255,255,.1)":"transparent",borderLeft:active===n.k?"3px solid #fff":"3px solid transparent",color:active===n.k?"#fff":"rgba(255,255,255,.5)",fontSize:12,fontWeight:active===n.k?600:400}}><span style={{fontSize:12}}>{n.e}</span>{n.l}</div>))}</div><div style={{padding:10,borderTop:"1px solid rgba(255,255,255,.1)"}}><div style={S.flex}><div style={{width:26,height:26,borderRadius:"50%",background:"rgba(255,255,255,.12)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,color:"#fff"}}>YA</div><div style={{flex:1}}><div style={{fontSize:10,fontWeight:600,color:"#fff"}}>Yassir Q.</div><div style={{fontSize:8,color:"rgba(255,255,255,.4)"}}>{persona?.label}</div></div></div><button onClick={onLogout} style={{marginTop:6,background:"rgba(255,255,255,.08)",border:"1px solid rgba(255,255,255,.15)",borderRadius:5,padding:"4px 0",width:"100%",color:"rgba(255,255,255,.6)",fontSize:9}}>Sign Out</button></div></div>);

// ═══ PAGES ═══
const PgDash=({go})=>(<div><div style={S.g4}>{[{l:"Employees",v:247,d:"+12",c:T.teal,p:"team"},{l:"AI Agents",v:5,d:"+2",c:T.violet,p:"team"},{l:"Positions",v:34,d:"-3",c:T.ocean,p:"marketplace"},{l:"Interviews",v:18,d:"+5",c:T.orange,p:"interviews"}].map(s=>(<div key={s.l} onClick={()=>go(s.p)} style={{...S.card,cursor:"pointer"}}><div style={S.between}><span style={{fontSize:18}}>{s.l==="AI Agents"?"🤖":s.l==="Employees"?"👥":s.l==="Positions"?"📋":"🎯"}</span><span style={{fontSize:10,fontWeight:700,color:s.d[0]==="+"?T.teal:T.red}}>{s.d}</span></div><div style={{fontSize:24,fontWeight:800,fontFamily:FH,marginTop:6}}>{s.v}</div><div style={{fontSize:11,color:T.inkMuted}}>{s.l}</div></div>))}</div><div style={S.g2}><div style={S.card}><h3 style={S.h3}>Pipeline</h3><div style={{marginTop:10}}>{["Scheduled","In Progress","Plan","Training","Done"].map((s,i)=>(<div key={s} style={{...S.flex,marginBottom:7}}><span style={{fontSize:10,color:T.inkMuted,width:100}}>{s}</span><div style={{flex:1}}><Bar pct={[25,45,60,35,80][i]} color={[T.ocean,T.orange,T.teal,T.violet,T.green][i]}/></div><span style={{fontSize:10,fontWeight:600,width:22,textAlign:"right"}}>{[12,18,24,9,31][i]}</span></div>))}</div></div><div style={S.card}><h3 style={S.h3}>AI Agents</h3><div style={{marginTop:10}}>{AI_AGENTS.slice(0,4).map(a=>(<div key={a.id} style={{...S.flex,padding:"5px 0",borderBottom:`1px solid ${T.border}`}}><span>🤖</span><div style={{flex:1}}><div style={{fontSize:11,fontWeight:600}}>{a.name}</div></div><Bd status={a.status}/></div>))}</div></div></div><div style={S.card}><h3 style={{...S.h3,marginBottom:8}}>Quick Actions</h3><div style={{display:"flex",gap:5,flexWrap:"wrap"}}>{[{l:"Interview",p:"interviews"},{l:"Marketplace",p:"marketplace"},{l:"Careers",p:"careers"},{l:"Charter",p:"charter"},{l:"Skills",p:"skills"}].map(a=>(<button key={a.l} onClick={()=>go(a.p)} style={{...S.btn,...S.btnO}}>{a.l}</button>))}</div></div></div>);

const PgCharter=()=>{const[exp,setExp]=useState({});return(<div><div style={{...S.card,background:`${T.axaBlue}04`,borderColor:`${T.axaBlue}18`}}><div style={S.flex}><span>⭐</span><span style={{fontSize:12,fontWeight:700,color:T.axaBlue}}>CORE PRINCIPLE</span></div><p style={{fontFamily:FH,fontSize:16,fontStyle:"italic",marginTop:6}}>"Human always stays accountable"</p></div>{CHARTER.map((sec,si)=>(<div key={si} style={S.card}><div style={{...S.between,cursor:"pointer"}} onClick={()=>setExp(p=>({...p,[si]:!p[si]}))}><div style={S.flex}><span>{sec.icon}</span><h3 style={S.h3}>{sec.title}</h3></div><span style={{color:T.inkMuted,transform:exp[si]?"rotate(90deg)":"none",display:"inline-block",transition:"transform .2s"}}>▶</span></div>{exp[si]&&<div style={{marginTop:8,borderTop:`1px solid ${T.border}`,paddingTop:8}}>{sec.items.map((it,i)=>(<div key={i} style={{padding:"5px 8px",background:i%2?T.bgMuted:"transparent",borderRadius:5,marginBottom:2}}><div style={{fontSize:11,fontWeight:600,color:T.teal}}>{it.t}</div><div style={{fontSize:11,color:T.inkSec}}>{it.c}</div>{it.hl&&<div style={{marginTop:3,padding:"3px 8px",background:T.orangeBg,borderLeft:`2px solid ${T.orange}`,borderRadius:3,fontSize:10,color:T.orange,fontWeight:600}}>{it.hl}</div>}</div>))}</div>}</div>))}</div>);};

const PgMarket=()=>{const[sf,setSf]=useState([]);const[df,setDf]=useState("All");const[q,setQ]=useState("");const[sel,setSel]=useState(null);const pool=EMP.filter(e=>e.mobility);const fil=pool.filter(e=>(df==="All"||e.dept===df)&&(sf.length===0||sf.some(s=>e.skills.includes(s)))&&(!q||e.name.toLowerCase().includes(q.toLowerCase())||e.role.toLowerCase().includes(q.toLowerCase())));
if(sel)return(<div><button onClick={()=>setSel(null)} style={{...S.btn,...S.btnO,...S.btnSm,marginBottom:10}}>← Back</button><div style={{...S.card,padding:22,border:`2px solid ${T.axaBlue}18`,maxWidth:660}}><div style={{fontSize:9,fontWeight:700,color:T.axaBlue,letterSpacing:1.5}}>WORKFORCE ID CARD</div><div style={{...S.flex,marginTop:10}}><div style={{width:48,height:48,borderRadius:"50%",background:T.axaBlue,display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,fontWeight:700,color:"#fff"}}>{sel.avatar}</div><div style={{flex:1}}><div style={{fontSize:16,fontWeight:700,fontFamily:FH}}>{sel.name}</div><div style={{fontSize:11,color:T.inkSec}}>{sel.role} — {sel.dept} · {sel.level}</div><div style={{fontSize:10,color:T.teal,marginTop:1}}>{sel.intent}</div></div></div><div style={{...S.g2,marginTop:12}}><div><div style={S.label}>Experience</div><div style={{fontSize:12}}>{sel.yrs}y</div><div style={{fontSize:10,color:T.inkMuted,marginTop:2}}>{sel.bg}</div></div><div><div style={S.label}>Teams</div>{sel.teams.map(t=><div key={t} style={{fontSize:11}}>• {t}</div>)}</div></div><div style={{marginTop:10}}><div style={S.label}>Skills</div><div style={{display:"flex",flexWrap:"wrap",gap:3,marginTop:3}}>{sel.skills.map((sk,i)=>(<div key={sk} style={{background:T.bgSoft,borderRadius:4,padding:"2px 7px",display:"inline-flex",alignItems:"center",gap:4}}><span style={{fontSize:10}}>{sk}</span><div style={{display:"flex",gap:1}}>{[1,2,3,4,5].map(l=><div key={l} style={{width:4,height:4,borderRadius:1,background:l<=3+i%3?T.teal:`${T.inkDim}33`}}/>)}</div></div>))}</div></div><div style={{marginTop:10}}><div style={S.label}>Performance</div><table style={{width:"100%",borderCollapse:"collapse",fontSize:10,marginTop:3}}><tbody>{sel.perf.map(p=>(<tr key={p.yr} style={{borderBottom:`1px solid ${T.border}`}}><td style={{padding:"4px 6px",fontWeight:600}}>{p.yr}</td><td style={{textAlign:"center"}}><span style={{fontWeight:700,color:p.score>=4?T.teal:T.orange}}>{p.score}</span></td><td style={{padding:"4px 6px",color:T.inkSec}}>{p.note}</td></tr>))}</tbody></table></div><div style={{...S.flex,marginTop:12}}><button style={S.btn}>📧 Contact</button><button style={{...S.btn,background:T.teal}}>🎯 Interview</button></div></div></div>);
return(<div><div style={{...S.card,padding:12}}><div style={{...S.flex,marginBottom:8}}><span style={{fontSize:12,fontWeight:600,color:T.teal}}>Mobility Talent</span>{(sf.length||df!=="All")&&<button onClick={()=>{setSf([]);setDf("All");setQ("");}} style={{...S.btn,...S.btnSm,...S.btnO,marginLeft:"auto"}}>Clear</button>}</div><div style={{...S.flex,gap:8,marginBottom:6}}><input style={{...S.input,maxWidth:180}} placeholder="Search..." value={q} onChange={e=>setQ(e.target.value)}/><select style={S.select} value={df} onChange={e=>setDf(e.target.value)}><option value="All">All Depts</option>{[...new Set(EMP.map(e=>e.dept))].map(d=><option key={d}>{d}</option>)}</select></div><Chips options={SKILLS.slice(0,14)} selected={sf} onToggle={s=>setSf(p=>p.includes(s)?p.filter(x=>x!==s):[...p,s])}/></div><div style={{fontSize:10,color:T.inkMuted,margin:"5px 0"}}>{fil.length} results</div><div style={S.g2}>{fil.map(e=>(<div key={e.id} style={{...S.card,cursor:"pointer"}} onClick={()=>setSel(e)}><div style={S.flex}><div style={{width:30,height:30,borderRadius:"50%",background:T.axaBlue,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,color:"#fff"}}>{e.avatar}</div><div style={{flex:1}}><div style={{fontSize:12,fontWeight:600}}>{e.name}</div><div style={{fontSize:10,color:T.inkMuted}}>{e.role}</div></div><Bd status={e.level}/></div><div style={{fontSize:10,color:T.teal,marginTop:4}}>{e.intent}</div><div style={{display:"flex",flexWrap:"wrap",gap:2,marginTop:5}}>{e.skills.slice(0,4).map(sk=><span key={sk} style={{...S.tag,fontSize:9}}>{sk}</span>)}</div></div>))}</div></div>);};

const PgTeam=()=>(<div><h3 style={{...S.h3,marginBottom:8}}>Human Team</h3><div style={S.g2}>{EMP.slice(0,8).map(e=>(<div key={e.id} style={S.card}><div style={S.flex}><div style={{width:28,height:28,borderRadius:"50%",background:T.axaBlue,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,color:"#fff"}}>{e.avatar}</div><div style={{flex:1}}><div style={{fontSize:11,fontWeight:600}}>{e.name}</div><div style={{fontSize:10,color:T.inkMuted}}>{e.role}</div></div><Bd status={e.level}/></div></div>))}</div><div style={{marginTop:16,paddingTop:12,borderTop:`2px solid ${T.violet}18`}}><div style={S.flex}><span>🤖</span><h3 style={{...S.h3,margin:0}}>AI Agents</h3></div><div style={{...S.g3,marginTop:8}}>{AI_AGENTS.map(a=>(<div key={a.id} style={{...S.card,borderLeft:`3px solid ${a.status==="active"?T.violet:a.status==="training"?T.orange:T.inkDim}`}}><div style={{fontSize:11,fontWeight:700}}>{a.name}</div><div style={{fontSize:10,color:T.inkMuted}}>{a.role}</div><div style={{...S.flex,marginTop:6}}><div style={{flex:1}}><Bar pct={a.accuracy} color={T.violet}/></div><span style={{fontSize:10,fontWeight:700,color:T.violet}}>{a.accuracy}%</span></div></div>))}</div></div></div>);

// ═══ INTERVIEWS — Fixed Save + Dynamic Q3 ═══
const PgIV=({persona})=>{const allPaths=useMemo(()=>genPaths(),[]);const[ivs,setIvs]=useState([{id:1,emp:EMP[0],date:"2026-04-25",st:"Scheduled",wf:0,ans:{},plan:null},{id:2,emp:EMP[1],date:"2026-04-22",st:"In Progress",wf:1,ans:{1:"Strategic / transversal"},plan:null},{id:3,emp:EMP[2],date:"2026-04-10",st:"Completed",wf:6,ans:{},plan:{target:"VP Product",pct:65,cur:EMP[2].skills,req:["Strategic Thinking","Financial Modeling","Leadership"],gaps:[{s:"Strategic Thinking",c:2,r:5,p:"High"},{s:"Financial Modeling",c:1,r:4,p:"High"},{s:"Leadership",c:3,r:5,p:"Medium"}],trains:[{n:"Product Leadership",pr:"AXA",d:"10w",st:"In progress"},{n:"Strategy",pr:"INSEAD",d:"6w",st:"Completed"}],certs:[{n:"CPM",pr:"AIPMM",st:"Achieved",dt:"03/26"},{n:"AI Strategy",pr:"MIT",st:"Registered",dt:"09/26"}],assess:[{n:"Strategy",st:"Completed",sc:78}],ms:[{t:"Gap",d:"02/26",s:"Completed"},{t:"Training",d:"03/26",s:"Completed"},{t:"Mid-review",d:"06/26",s:"In Progress"},{t:"Certs",d:"12/26",s:"Planned"}]}},{id:4,emp:EMP[4],date:"2026-04-18",st:"Action Plan",wf:3,ans:{},plan:{target:"HR Director",pct:25,cur:EMP[4].skills,req:["Strategic Thinking","Financial Modeling","Data Governance"],gaps:[{s:"Strategic Thinking",c:2,r:5,p:"High"},{s:"Financial Modeling",c:0,r:4,p:"High"},{s:"Data Governance",c:1,r:3,p:"Medium"}],trains:[{n:"HR Strategy",pr:"AXA",d:"12w",st:"Not started"},{n:"Analytics",pr:"Coursera",d:"8w",st:"Not started"}],certs:[{n:"SHRM",pr:"SHRM",st:"Planned",dt:"12/26"}],assess:[{n:"Leadership",st:"Planned",sc:null}],ms:[{t:"Gap",d:"05/26",s:"In Progress"},{t:"Training",d:"06/26",s:"Planned"},{t:"Certs",d:"03/27",s:"Planned"}]}}]);
const[v,setV]=useState("list");const[aiv,setAiv]=useState(null);const[cq,setCq]=useState(0);const[ans,setAns]=useState({});const[ft,setFt]=useState({});const[ma,setMa]=useState({});const[pv,setPv]=useState(null);const[pt,setPt]=useState("gap");const[showSched,setShowSched]=useState(false);const[schedEmp,setSchedEmp]=useState("");const[schedDate,setSchedDate]=useState("2026-05-05");const[saved,setSaved]=useState(false);

const startIV=iv=>{setAiv(iv);setAns(iv.ans||{});setFt({});setMa({});setCq(0);setV("iv");setSaved(false);};
// ═══ FIXED SAVE ═══
const doSave=()=>{const a={...ans};Object.entries(ma).forEach(([k,vl])=>{a[k]=vl.join(", ");});Object.entries(ft).forEach(([k,vl])=>{if(vl)a[k]=vl;});setIvs(p=>p.map(i=>i.id===aiv.id?{...i,st:"In Progress",wf:1,ans:a}:i));setAiv(prev=>({...prev,ans:a}));setSaved(true);setTimeout(()=>setSaved(false),2500);};
const genP=(emp,a)=>{const target=a[3]||a["3c"]||`Senior ${emp.role}`;const cur=a[4]?a[4].split(", "):emp.skills;const des=a[6]?a[6].split(", "):SKILLS.slice(5,10);const req=[...des.filter(s=>!cur.includes(s)),"Strategic Thinking","Leadership"].slice(0,5);return{target,pct:10,cur,req,gaps:req.map(s=>({s,c:Math.floor(Math.random()*2),r:3+Math.floor(Math.random()*3),p:["High","Medium","Low"][Math.floor(Math.random()*3)]})),trains:[{n:"Leadership",pr:"AXA",d:"12w",st:"Not started"},{n:"AI Leaders",pr:"MIT",d:"8w",st:"Not started"},{n:"Strategy",pr:"INSEAD",d:"6w",st:"Not started"}],certs:[{n:"AWS",pr:"AWS",st:"Planned",dt:"09/26"},{n:"PMP",pr:"PMI",st:"Planned",dt:"12/26"}],assess:[{n:"Baseline",st:"Planned",sc:null},{n:"Mid",st:"Planned",sc:null}],ms:[{t:"Gap",d:"05/26",s:"In Progress"},{t:"Training",d:"06/26",s:"Planned"},{t:"Certs",d:"12/26",s:"Planned"},{t:"Transition",d:"03/27",s:"Planned"}]};};
const complIV=()=>{const a={...ans};Object.entries(ma).forEach(([k,vl])=>{a[k]=vl.join(", ");});Object.entries(ft).forEach(([k,vl])=>{if(vl)a[k]=vl;});setIvs(p=>p.map(i=>i.id===aiv.id?{...i,st:"Gap Analysis",wf:2,ans:a,plan:genP(aiv.emp,a)}:i));setAiv(null);setV("list");};
const doSchedule=()=>{if(!schedEmp)return;const emp=EMP.find(e=>e.name===schedEmp);if(!emp)return;setIvs(p=>[...p,{id:Date.now(),emp,date:schedDate,st:"Scheduled",wf:0,ans:{},plan:null}]);setShowSched(false);setSchedEmp("");};
const WFS=({step})=>(<div style={{display:"flex",alignItems:"center",margin:"6px 0"}}>{WF.map((s,i)=>(<div key={i} style={{display:"flex",alignItems:"center",flex:1}}><div style={{display:"flex",flexDirection:"column",alignItems:"center"}}><div style={{width:18,height:18,borderRadius:"50%",fontSize:8,fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center",background:i<step?T.teal:i===step?T.tealBg:T.bgSoft,color:i<step?"#fff":i===step?T.teal:T.inkDim,border:i===step?`2px solid ${T.teal}`:"none"}}>{i<step?"✓":i+1}</div><div style={{fontSize:6,color:i<=step?T.ink:T.inkDim,marginTop:1,textAlign:"center",maxWidth:42}}>{s}</div></div>{i<WF.length-1&&<div style={{flex:1,height:1,background:i<step?T.teal:T.bgSoft,marginBottom:10}}/>}</div>))}</div>);

// ACTION PLAN
if(v==="plan"&&pv){const p=pv.plan;const emp=pv.emp;const tabs=[{k:"gap",l:"🔬Gap",c:T.red},{k:"train",l:"📚Train",c:T.ocean},{k:"cert",l:"🏅Cert",c:T.orange},{k:"assess",l:"📝Assess",c:T.violet},{k:"ms",l:"📅Timeline",c:T.teal},{k:"form",l:"📋Form",c:T.axaBlue}];
return(<div><button onClick={()=>setV("list")} style={{...S.btn,...S.btnO,...S.btnSm,marginBottom:8}}>← Back</button>
<div style={S.between}><div><h2 style={S.h1}>Plan: {emp.name}</h2><p style={{fontSize:11,color:T.inkSec,marginTop:1}}>{emp.role} → <strong style={{color:T.teal}}>{p.target}</strong></p></div><div style={{fontSize:26,fontWeight:800,fontFamily:FH,color:T.teal}}>{p.pct}%</div></div>
<div style={{display:"flex",gap:3,marginTop:8,flexWrap:"wrap"}}>{tabs.map(tb=>(<button key={tb.k} onClick={()=>setPt(tb.k)} style={{...S.btn,...S.btnSm,background:pt===tb.k?tb.c:T.bgSoft,color:pt===tb.k?"#fff":T.inkSec,border:`1px solid ${pt===tb.k?tb.c:T.border}`}}>{tb.l}</button>))}</div>
{pt==="gap"&&<div style={{...S.card,marginTop:8}}><h3 style={{...S.h3,marginBottom:8}}>Gap</h3><div style={S.g2}><div><div style={S.label}>Current</div><div style={{display:"flex",flexWrap:"wrap",gap:2,marginTop:2}}>{p.cur.map(s=><span key={s} style={S.tag}>{s}</span>)}</div></div><div><div style={S.label}>Gaps</div><div style={{display:"flex",flexWrap:"wrap",gap:2,marginTop:2}}>{p.req.map(s=><span key={s} style={{...S.tag,background:T.redBg,color:T.red}}>{s}</span>)}</div></div></div><div style={{marginTop:10}}>{p.gaps.map((g,i)=>(<div key={i} style={{...S.flex,padding:"5px 0",borderBottom:`1px solid ${T.border}`}}><span style={{fontSize:11,fontWeight:600,width:120}}>{g.s}</span><div style={{flex:1,...S.flex}}><span style={{fontSize:9,width:28}}>Lv{g.c}</span><div style={{flex:1}}><Bar pct={g.c/g.r*100} color={g.c>=g.r?T.teal:g.c>=g.r/2?T.orange:T.red}/></div><span style={{fontSize:9,width:36}}>→Lv{g.r}</span></div><Bd status={g.p}/><button onClick={()=>setPt("train")} style={{...S.btn,...S.btnSm,...S.btnO,padding:"1px 5px",fontSize:8}}>→</button></div>))}</div><button onClick={()=>setPt("train")} style={{...S.btn,...S.btnG,marginTop:8}}>Training →</button></div>}
{pt==="train"&&<div style={{...S.card,marginTop:8}}><h3 style={{...S.h3,marginBottom:8}}>Training</h3>{p.trains.map((t,i)=>(<div key={i} style={{padding:8,background:T.bgMuted,borderRadius:6,marginBottom:4}}><div style={S.between}><div style={{fontSize:11,fontWeight:600}}>{t.n} <span style={{fontWeight:400,color:T.inkMuted}}>· {t.pr} · {t.d}</span></div><Bd status={t.st}/></div><div style={{marginTop:3}}><Bar pct={t.st==="Completed"?100:t.st==="In progress"?50:0} color={T.ocean}/></div></div>))}<div style={S.flex}><button onClick={()=>setPt("gap")} style={{...S.btn,...S.btnSm,...S.btnO}}>←Gap</button><button onClick={()=>setPt("cert")} style={{...S.btn,...S.btnSm,...S.btnG}}>Cert→</button></div></div>}
{pt==="cert"&&<div style={{...S.card,marginTop:8}}><h3 style={{...S.h3,marginBottom:8}}>Certifications</h3>{p.certs.map((c,i)=>(<div key={i} style={{...S.flex,padding:"6px 0",borderBottom:`1px solid ${T.border}`}}><span>🎓</span><div style={{flex:1}}><div style={{fontSize:11,fontWeight:600}}>{c.n}</div><div style={{fontSize:10,color:T.inkMuted}}>{c.pr} · {c.dt}</div></div><Bd status={c.st}/></div>))}<div style={S.flex}><button onClick={()=>setPt("train")} style={{...S.btn,...S.btnSm,...S.btnO}}>←</button><button onClick={()=>setPt("assess")} style={{...S.btn,...S.btnSm,...S.btnG}}>Assess→</button></div></div>}
{pt==="assess"&&<div style={{...S.card,marginTop:8}}><h3 style={{...S.h3,marginBottom:8}}>Assessments</h3>{p.assess.map((a,i)=>(<div key={i} style={{...S.flex,padding:"6px 0",borderBottom:`1px solid ${T.border}`}}><div style={{flex:1,fontSize:11,fontWeight:600}}>{a.n}</div>{a.sc!=null&&<span style={{fontWeight:700,color:a.sc>=70?T.teal:T.orange}}>{a.sc}%</span>}<Bd status={a.st}/></div>))}<div style={S.flex}><button onClick={()=>setPt("cert")} style={{...S.btn,...S.btnSm,...S.btnO}}>←</button><button onClick={()=>setPt("ms")} style={{...S.btn,...S.btnSm,...S.btnG}}>Timeline→</button></div></div>}
{pt==="ms"&&<div style={{...S.card,marginTop:8}}><h3 style={{...S.h3,marginBottom:8}}>Timeline</h3>{p.ms.map((m,i)=>(<div key={i} style={{...S.flex,padding:"5px 0",borderBottom:`1px solid ${T.border}`}}><div style={{width:18,height:18,borderRadius:"50%",background:m.s==="Completed"?T.teal:m.s==="In Progress"?T.tealBg:T.bgSoft,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:m.s==="Completed"?"#fff":T.inkDim}}>{m.s==="Completed"?"✓":i+1}</div><div style={{flex:1}}><div style={{fontSize:11}}>{m.t}</div><div style={{fontSize:9,color:T.inkMuted}}>{m.d}</div></div><Bd status={m.s}/></div>))}<button onClick={()=>setPt("form")} style={{...S.btn,...S.btnG,marginTop:8}}>Form→</button></div>}
{pt==="form"&&<div style={{...S.card,marginTop:8}}><h3 style={{...S.h3,marginBottom:8}}>Action Plan Form</h3><div style={{marginBottom:10}}><label style={S.label}>Target</label><input style={S.input} defaultValue={p.target}/></div><div style={{marginBottom:10}}><label style={S.label}>Readiness</label><select style={{...S.select,width:"100%"}}><option>1</option><option>2</option><option>3</option><option>4</option><option>5</option></select></div><div style={{marginBottom:10}}><label style={S.label}>Gaps</label><div style={{display:"flex",flexWrap:"wrap",gap:2}}>{p.req.map(s=><span key={s} style={{...S.tag,background:T.redBg,color:T.red}}>{s}</span>)}</div></div><div style={{marginBottom:10}}><label style={S.label}>Timeline</label><select style={{...S.select,width:"100%"}}><option>3-6mo</option><option>6-12mo</option><option>12-18mo</option></select></div><div style={{marginBottom:10}}><label style={S.label}>Manager Notes</label><textarea style={{...S.input,minHeight:50}}/></div><div style={{marginBottom:10}}><label style={S.label}>Employee Notes</label><textarea style={{...S.input,minHeight:50}}/></div><div style={{marginBottom:10}}><label style={S.label}>Next Review</label><input style={S.input} type="date" defaultValue="2026-08-01"/></div><div style={S.flex}><button style={S.btn}>💾 Save</button><button style={{...S.btn,...S.btnG}}>✅ Finalize</button></div></div>}
</div>);}

// INTERVIEW FORM
if(v==="iv"&&aiv){const curQ=IQ[cq];const show=!curQ.on||ans[curQ.on]===curQ.val;
const jobSugg=useMemo(()=>getJobSuggestions(aiv.emp,allPaths),[aiv.emp.id]);
return(<div><button onClick={()=>setV("list")} style={{...S.btn,...S.btnO,...S.btnSm,marginBottom:8}}>← Back</button>
<div style={S.between}><div><h2 style={S.h1}>Interview: {aiv.emp.name}</h2><p style={{fontSize:11,color:T.inkSec}}>{aiv.emp.role} — {aiv.emp.dept}</p></div><div style={S.flex}>{saved&&<span style={{fontSize:11,color:T.teal,fontWeight:600,animation:"fadeUp .3s"}}>✅ Saved!</span>}<button onClick={doSave} style={{...S.btn,...S.btnSm}}>💾 Save</button></div></div>
<div style={{margin:"6px 0"}}><Bar pct={(cq+1)/IQ.length*100}/><div style={{fontSize:10,color:T.inkMuted,marginTop:2}}>Q{cq+1}/{IQ.length}</div></div>
{show?(<div style={{...S.card,padding:18,marginTop:6}}>
<div style={{fontSize:10,color:T.teal,fontWeight:700,letterSpacing:1}}>Q{String(curQ.id)}</div>
<h3 style={{fontFamily:FH,fontSize:15,fontWeight:700,margin:"4px 0 10px",lineHeight:1.3}}>{curQ.q}</h3>
{curQ.note&&<div style={{fontSize:10,color:T.orange,marginBottom:8}}>ℹ️ {curQ.note}</div>}
{curQ.t==="s"&&curQ.o.map(opt=>(<div key={opt} onClick={()=>setAns(p=>({...p,[curQ.id]:opt}))} style={{padding:"8px 10px",margin:"3px 0",borderRadius:6,cursor:"pointer",border:`1.5px solid ${ans[curQ.id]===opt?T.teal:T.border}`,background:ans[curQ.id]===opt?T.tealBg:"transparent"}}><div style={S.flex}><div style={{width:14,height:14,borderRadius:"50%",border:`2px solid ${ans[curQ.id]===opt?T.teal:T.inkDim}`,display:"flex",alignItems:"center",justifyContent:"center"}}>{ans[curQ.id]===opt&&<div style={{width:6,height:6,borderRadius:"50%",background:T.teal}}/>}</div><span style={{fontSize:12,color:ans[curQ.id]===opt?T.ink:T.inkSec}}>{opt}</span></div></div>))}
{curQ.t==="m"&&<Chips options={curQ.o} selected={ma[curQ.id]||[]} onToggle={val=>setMa(p=>{const c=p[curQ.id]||[];return{...p,[curQ.id]:c.includes(val)?c.filter(x=>x!==val):[...c,val]};})} max={curQ.o.length}/>}
{curQ.t==="x"&&<textarea style={{...S.input,minHeight:60}} placeholder="Response..." value={ft[curQ.id]||""} onChange={e=>setFt(p=>({...p,[curQ.id]:e.target.value}))}/>}
{/* ═══ DYNAMIC JOB SELECTOR for Q3 ═══ */}
{curQ.t==="job"&&(<div>
  <div style={{fontSize:11,fontWeight:600,marginBottom:5}}>Suggested roles ({aiv.emp.role} path):</div>
  <div style={{display:"flex",flexWrap:"wrap",gap:4,marginBottom:10}}>
    {jobSugg.map(j=>(<span key={j} onClick={()=>setAns(p=>({...p,[curQ.id]:j}))} style={{...S.badge,cursor:"pointer",padding:"5px 10px",fontSize:11,background:ans[curQ.id]===j?T.tealBg:T.bgSoft,color:ans[curQ.id]===j?T.teal:T.inkSec,border:`1.5px solid ${ans[curQ.id]===j?T.teal:T.border}`,borderRadius:6}}>{j}</span>))}
  </div>
  <div style={{fontSize:11,fontWeight:600,marginBottom:3}}>Or custom:</div>
  <input style={S.input} placeholder="e.g. Agentic AI Lead, VP Data..." value={ft["3c"]||""} onChange={e=>{setFt(p=>({...p,"3c":e.target.value}));if(e.target.value)setAns(p=>({...p,[curQ.id]:e.target.value}));}}/>
  {ans[curQ.id]&&<div style={{marginTop:6,padding:"4px 8px",background:T.tealBg,borderRadius:5,fontSize:10,color:T.teal,fontWeight:600}}>→ {ans[curQ.id]}</div>}
</div>)}
{curQ.t!=="x"&&curQ.t!=="job"&&<div style={{marginTop:8}}><div style={{fontSize:9,color:T.inkMuted}}>Notes</div><textarea style={{...S.input,minHeight:30}} value={ft[`${curQ.id}n`]||""} onChange={e=>setFt(p=>({...p,[`${curQ.id}n`]:e.target.value}))}/></div>}
</div>):(<div style={{...S.card,padding:18,marginTop:6,textAlign:"center",color:T.inkMuted}}>⏭️ Skipped</div>)}
<div style={{...S.between,marginTop:8}}><button onClick={()=>setCq(p=>Math.max(0,p-1))} disabled={cq===0} style={{...S.btn,...S.btnO}}>←</button>{cq<IQ.length-1?<button onClick={()=>setCq(p=>p+1)} style={S.btn}>Next→</button>:<button onClick={complIV} style={{...S.btn,...S.btnG}}>✅ Complete→Gap</button>}</div>
</div>);}

// Schedule modal
const SchedM=()=>showSched?(<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.3)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}} onClick={()=>setShowSched(false)}><div style={{...S.card,width:360,padding:22,animation:"popIn .3s ease"}} onClick={e=>e.stopPropagation()}><h3 style={S.h3}>Schedule Interview</h3><div style={{marginTop:10,marginBottom:8}}><label style={S.label}>Employee</label><select style={{...S.select,width:"100%"}} value={schedEmp} onChange={e=>setSchedEmp(e.target.value)}><option value="">Select...</option>{EMP.map(e=><option key={e.id} value={e.name}>{e.name} — {e.role}</option>)}</select></div><div style={{marginBottom:8}}><label style={S.label}>Date</label><input style={S.input} type="date" value={schedDate} onChange={e=>setSchedDate(e.target.value)}/></div><div style={S.flex}><button onClick={doSchedule} style={S.btn}>✅ Schedule</button><button onClick={()=>setShowSched(false)} style={{...S.btn,...S.btnO}}>Cancel</button></div></div></div>):null;

// LIST
return(<div><SchedM/><div style={S.between}><div/><button onClick={()=>setShowSched(true)} style={S.btn}>+ Schedule</button></div>{ivs.map(iv=>(<div key={iv.id} style={S.card}><div style={S.between}><div style={S.flex}><div style={{width:30,height:30,borderRadius:"50%",background:T.axaBlue,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,color:"#fff"}}>{iv.emp.avatar}</div><div><div style={{fontSize:12,fontWeight:600}}>{iv.emp.name}</div><div style={{fontSize:10,color:T.inkMuted}}>{iv.emp.role}</div></div></div><div style={S.flex}><span style={{fontSize:10,color:T.inkMuted}}>{iv.date}</span><Bd status={iv.st}/></div></div><WFS step={iv.wf}/><div style={{display:"flex",gap:4,flexWrap:"wrap"}}>{iv.st==="Scheduled"&&<button onClick={()=>startIV(iv)} style={{...S.btn,...S.btnSm}}>▶ Start</button>}{iv.st==="In Progress"&&<button onClick={()=>startIV(iv)} style={{...S.btn,...S.btnSm}}>↺ Resume</button>}{iv.plan&&<button onClick={()=>{setPv(iv);setPt("gap");setV("plan");}} style={{...S.btn,...S.btnSm,...S.btnG}}>📋 Plan</button>}{iv.plan&&<button onClick={()=>{setPv(iv);setPt("gap");setV("plan");}} style={{...S.btn,...S.btnSm,background:T.red,color:"#fff"}}>🔬Gap</button>}</div></div>))}</div>);};

// ═══ CAREERS ═══
const PgCareer=()=>{const all=useMemo(()=>genPaths(),[]);const[df,setDf]=useState("All");const[q,setQ]=useState("");const[exp,setExp]=useState(null);const[pg,setPg]=useState(0);const pp=12;const fil=all.filter(p=>(df==="All"||p.domain===df)&&(!q||p.name.toLowerCase().includes(q.toLowerCase())||p.steps.some(s=>s.title.toLowerCase().includes(q.toLowerCase()))));const paged=fil.slice(pg*pp,(pg+1)*pp);const tp=Math.ceil(fil.length/pp);
const Graph=({steps})=>(<div style={{padding:"8px 0",overflowX:"auto"}}><div style={{display:"flex",alignItems:"flex-start",minWidth:steps.length*100}}>{steps.map((s,i)=>(<div key={i} style={{display:"flex",alignItems:"center"}}><div style={{textAlign:"center",width:85}}><div style={{width:30,height:30,borderRadius:7,background:i===0?T.tealBg:i===steps.length-1?`${T.axaBlue}08`:T.bgMuted,border:`2px solid ${i===0?T.teal:i===steps.length-1?T.axaBlue:T.border}`,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto",fontSize:9,fontWeight:700,color:i===0?T.teal:i===steps.length-1?T.axaBlue:T.inkSec}}>L{s.level}</div><div style={{fontSize:9,fontWeight:600,marginTop:3,lineHeight:1.2}}>{s.title}</div><div style={{display:"flex",flexWrap:"wrap",gap:1,justifyContent:"center",marginTop:2}}>{s.skills.map(sk=><span key={sk} style={{fontSize:6,background:T.tealBg,color:T.teal,padding:"0 3px",borderRadius:2}}>{sk}</span>)}</div></div>{i<steps.length-1&&<svg width="16" height="12" viewBox="0 0 16 12" style={{margin:"0 -2px",marginBottom:22}}><path d="M2 6h12m-3-3l3 3-3 3" stroke={T.teal} strokeWidth="1.5" fill="none" strokeLinecap="round"/></svg>}</div>))}</div></div>);
return(<div><div style={{...S.card,padding:10}}><div style={{...S.flex,gap:6}}><input style={{...S.input,maxWidth:160}} placeholder="Search..." value={q} onChange={e=>{setQ(e.target.value);setPg(0);}}/><select style={S.select} value={df} onChange={e=>{setDf(e.target.value);setPg(0);}}><option value="All">All</option>{DOMAINS.map(d=><option key={d}>{d}</option>)}</select><span style={{fontSize:10,color:T.inkMuted,marginLeft:"auto"}}>{fil.length}</span></div></div>
<div style={{display:"flex",flexWrap:"wrap",gap:3,margin:"5px 0"}}>{DOMAINS.map(d=><span key={d} onClick={()=>{setDf(df===d?"All":d);setPg(0);}} style={{...S.badge,cursor:"pointer",background:df===d?T.tealBg:T.bgSoft,color:df===d?T.teal:T.inkMuted,border:`1px solid ${df===d?T.teal:"transparent"}`}}>{d}</span>)}</div>
<div style={S.g3}>{paged.map(p=>(<div key={p.id} style={{...S.card,cursor:"pointer"}} onClick={()=>setExp(exp===p.id?null:p.id)}><div style={S.between}><Bd status={p.domain} custom={T.teal}/><Bd status={p.type} custom={T.violet}/></div><h4 style={{fontSize:11,fontWeight:700,margin:"5px 0 2px"}}>{p.name}</h4><div style={{display:"flex",alignItems:"center",gap:0,margin:"5px 0"}}>{p.steps.map((_,i)=><div key={i} style={{flex:1,display:"flex",alignItems:"center"}}><div style={{width:4,height:4,borderRadius:"50%",background:i===0?T.teal:i===p.steps.length-1?T.axaBlue:T.border}}/>{i<p.steps.length-1&&<div style={{flex:1,height:1,background:T.border}}/>}</div>)}</div>{exp===p.id&&<Graph steps={p.steps}/>}</div>))}</div>
<div style={{...S.flex,justifyContent:"center",marginTop:8,gap:5}}><button disabled={pg===0} onClick={()=>setPg(p=>p-1)} style={{...S.btn,...S.btnSm,...S.btnO}}>←</button><span style={{fontSize:10,color:T.inkMuted}}>{pg+1}/{tp}</span><button disabled={pg>=tp-1} onClick={()=>setPg(p=>p+1)} style={{...S.btn,...S.btnSm,...S.btnO}}>→</button></div></div>);};

// ═══ SKILLS ═══
const PgSkills=()=>{const[q,setQ]=useState("");const[showAdd,setShowAdd]=useState(false);const[newSk,setNewSk]=useState("");const[added,setAdded]=useState([]);const[aiM,setAiM]=useState(null);const allSk=[...SKILLS,...added];
const addSk=()=>{if(!newSk.trim())return;if(allSk.find(s=>s.toLowerCase()===newSk.trim().toLowerCase())){alert("Duplicate!");return;}setAdded(p=>[...p,newSk.trim()]);setNewSk("");setShowAdd(false);};
return(<div><div style={S.between}><span style={{fontSize:11,color:T.inkMuted}}>{allSk.length} skills</span><button onClick={()=>setShowAdd(true)} style={S.btn}>+ Add</button></div>
{showAdd&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.3)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}} onClick={()=>setShowAdd(false)}><div style={{...S.card,width:340,padding:20}} onClick={e=>e.stopPropagation()}><h3 style={S.h3}>Add Skill</h3><div style={{marginTop:8,marginBottom:6}}><label style={S.label}>Name</label><input style={S.input} value={newSk} onChange={e=>setNewSk(e.target.value)}/></div><div style={S.flex}><button onClick={addSk} style={S.btn}>Add</button><button onClick={()=>setShowAdd(false)} style={{...S.btn,...S.btnO}}>Cancel</button></div></div></div>}
{aiM&&<div style={{...S.card,background:T.violetBg,marginTop:8}}><div style={S.between}><span style={{fontSize:11,fontWeight:700,color:T.violet}}>🤖 {aiM.s}</span><button onClick={()=>setAiM(null)} style={{background:"none",border:"none",color:T.inkMuted,fontSize:12}}>✕</button></div><div style={{fontSize:10,color:T.inkSec,marginTop:3}}>Roles: {aiM.r.join(", ")} · Pairs: {aiM.m.join(", ")}</div></div>}
<input style={{...S.input,maxWidth:260,marginTop:8,marginBottom:8}} placeholder="Search..." value={q} onChange={e=>setQ(e.target.value)}/>
{Object.entries(SKILL_CATS).map(([cat,sks])=>{const f=[...sks,...(cat==="Technical"?added:[])].filter(s=>!q||s.toLowerCase().includes(q.toLowerCase()));if(!f.length)return null;return<div key={cat} style={S.card}><h3 style={{...S.h3,marginBottom:6}}>{cat}</h3><div style={{display:"flex",flexWrap:"wrap",gap:4}}>{f.map(s=>(<div key={s} onClick={()=>setAiM({s,r:["ML Eng","PM","Architect"].slice(0,1+Math.floor(Math.random()*2)),m:SKILLS.slice(Math.floor(Math.random()*8),Math.floor(Math.random()*8)+2)})} style={{background:T.bgMuted,border:`1px solid ${T.border}`,borderRadius:5,padding:"4px 8px",display:"inline-flex",alignItems:"center",gap:4,cursor:"pointer"}}><span style={{fontSize:10}}>{s}</span><div style={{display:"flex",gap:1}}>{[1,2,3,4,5].map(l=><div key={l} style={{width:3,height:3,borderRadius:1,background:l<=3?T.teal:`${T.inkDim}33`}}/>)}</div></div>))}</div></div>;})}
</div>);};

// ═══ WORKFLOWS ═══
const PgWF=()=>{const[exp,setExp]=useState(null);const wfs=[{id:1,n:"Interview — Sophie",tp:"Career",st:4,tot:7,s:"In Progress",h:["Scheduled","Started","Gap","Plan","Training..."]},{id:2,n:"Agent — LearnRec",tp:"Deploy",st:3,tot:5,s:"In Progress",h:["Config","Data","Training","Validating..."]},{id:3,n:"Assessment Q2",tp:"Assessment",st:5,tot:5,s:"Completed",h:["Init","Self","Review","Calibration","Done"]}];
return(<div>{wfs.map(w=>(<div key={w.id} style={S.card}><div style={S.between}><div style={{fontSize:12,fontWeight:700}}>{w.n}</div><div style={S.flex}><Bd status={w.s}/>{w.s==="In Progress"&&<button style={{...S.btn,...S.btnSm}}>↺</button>}</div></div><div style={{margin:"5px 0"}}><Bar pct={w.st/w.tot*100}/></div><div style={{cursor:"pointer",fontSize:10,color:T.teal}} onClick={()=>setExp(exp===w.id?null:w.id)}>{exp===w.id?"▼":"▶"} History</div>{exp===w.id&&<div style={{marginTop:4}}>{w.h.map((h,i)=><div key={i} style={{...S.flex,padding:"2px 0"}}><div style={{width:5,height:5,borderRadius:"50%",background:i<w.st?T.teal:T.bgSoft}}/><span style={{fontSize:10,color:i<w.st?T.ink:T.inkMuted}}>{h}</span></div>)}</div>}</div>))}</div>);};

// ═══ REPORTS ═══
const PgRep=()=>(<div><div style={S.g4}>{[{l:"Mobility",v:"23%",p:77,c:T.teal},{l:"Fill",v:"18d",p:90,c:T.green},{l:"Skills",v:"72%",p:85,c:T.ocean},{l:"Plans",v:"42",p:70,c:T.violet}].map(m=>(<div key={m.l} style={S.card}><div style={{fontSize:9,color:T.inkMuted,textTransform:"uppercase",fontWeight:600}}>{m.l}</div><div style={{fontSize:22,fontWeight:800,fontFamily:FH,color:m.c,margin:"3px 0"}}>{m.v}</div><Bar pct={m.p} color={m.c}/></div>))}</div><div style={S.g2}><div style={S.card}><h3 style={{...S.h3,marginBottom:6}}>By Domain</h3>{DOMAINS.slice(0,5).map((d,i)=>(<div key={d} style={{...S.flex,marginBottom:5}}><span style={{fontSize:10,color:T.inkMuted,width:90}}>{d}</span><div style={{flex:1}}><Bar pct={[65,82,45,58,73][i]}/></div><span style={{fontSize:10,fontWeight:600,width:24,textAlign:"right"}}>{[65,82,45,58,73][i]}%</span></div>))}</div><div style={S.card}><h3 style={{...S.h3,marginBottom:6}}>AI Agents</h3>{AI_AGENTS.map(a=>(<div key={a.id} style={{...S.flex,marginBottom:5}}><span style={{fontSize:10,width:80}}>{a.name}</span><div style={{flex:1}}><Bar pct={a.accuracy} color={T.violet}/></div><span style={{fontSize:10,fontWeight:700,color:T.violet,width:24,textAlign:"right"}}>{a.accuracy}%</span></div>))}</div></div></div>);

// ═══ MAIN ═══
export default function App(){
  const[auth,setAuth]=useState(false);const[persona,setPersona]=useState(null);const[pg,setPg]=useState("dashboard");
  if(!auth)return<Auth onLogin={p=>{setPersona(p);setAuth(true);}}/>;
  const titles={dashboard:"Dashboard",charter:"Smart Charter",marketplace:"Marketplace",team:"My Team",interviews:"Career Interviews",careers:"Career Paths",skills:"Skills Repository",workflows:"Workflows",reports:"Reports"};
  const pages={dashboard:<PgDash go={setPg}/>,charter:<PgCharter/>,marketplace:<PgMarket/>,team:<PgTeam/>,interviews:<PgIV persona={persona}/>,careers:<PgCareer/>,skills:<PgSkills/>,workflows:<PgWF/>,reports:<PgRep/>};
  return(<div style={{fontFamily:FT,background:T.bg,color:T.ink,minHeight:"100vh",display:"flex",overflow:"hidden",height:"100vh",fontSize:12}}><style>{css}</style><Side active={pg} go={setPg} persona={persona} onLogout={()=>{setAuth(false);setPersona(null);setPg("dashboard");}}/><div style={{flex:1,overflow:"auto",padding:"0 22px 22px"}}><div style={{...S.between,padding:"10px 0 12px",borderBottom:`1px solid ${T.border}`,marginBottom:12}}><div><h1 style={S.h1}>{titles[pg]}</h1><p style={{fontSize:10,color:T.inkMuted,marginTop:1}}>Mobility by Design · AXA Group Ops</p></div><div style={S.flex}><Bd status={persona?.label} custom={persona?.color}/></div></div>{pages[pg]}</div></div>);
}
